#include <stdio.h>
#include <string.h>
#define MAX 10100000
int isCiel(int num) {
    int count[10] = {0};
    while (num > 0) {
        count[num % 10]++;
        num /= 10;
    }
    return count[8] >= count[5] && count[5] >= count[3] && count[0] == 0 && count[1] == 0 && count[2] == 0 && count[4] == 0 && count[6] == 0 && count[7] == 0 && count[9] == 0;
}
int isXPseudoCiel(int num, int x) {
    if (x == 0) return isCiel(num);
    for (int i = 1; i <= 9; i++) {
        int temp = num;
        int count = 0;
        while (temp > 0) {
            if (temp % 10 == i) {
                count++;
            }
            temp /= 10;
        }
        if (count > 0) {
            temp = num;
            int pos = 0;
            while (temp > 0) {
                if (temp % 10 == i) {
                    temp /= 10;
                    pos = 1;
                    break;
                }
                temp /= 10;
            }
            if (pos == 1) {
                temp = num;
                int newNum = 0;
                int mul = 1;
                while (temp > 0) {
                    if (temp % 10 == i) {
                        newNum += (i - 1) * mul;
                    } else {
                        newNum += temp % 10 * mul;
                    }
                    mul *= 10;
                    temp /= 10;
                }
                if (isXPseudoCiel(newNum, x - 1)) return 1;
            }
        }
    }
    return 0;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x, N;
        scanf("%d %d", &x, &N);
        int ans = -1;
        for (int i = N; i >= 1; i--) {
            if (isXPseudoCiel(i, x)) {
                ans = i;
                break;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

